import json
from yaml import Loader, safe_load

def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r') as stream:
            yaml_content = safe_load(stream, Loader=Loader)
            return json.dumps(yaml_content)
    except FileNotFoundError:
        return f"Error: File not found at {yaml_file_path}"
    except yaml.YAMLError as e:
        return f"Error: Invalid YAML content - {str(e)}"
    except Exception as e:
        return f"Error: An error occurred while converting to JSON - {str(e)}"

from typing import Dict
import lxml.etree as etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data)
    students = root.findall(".//student")

    for student in students:
        if (student.find("username").text == username and 
            student.find("password").text == password):
            return {
                "name": student.find("name").text,
                "citizenship": student.find("citizenship").text,
                "age": student.find("age").text
            }

    return None

